// AUTO-GENERATED DRAFT SCREEN: AccountSetup
import React, { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Switch } from '@/components/ui/switch';
import { useMutation } from '@tanstack/react-query'; // Placeholder for tRPC mutation

// --- Schema Definition ---
const accountSetupSchema = z.object({
  walletAddress: z.string().min(1, 'Wallet address is required').regex(/^0x[a-fA-F0-9]{40}$/, 'Invalid Ethereum address'),
  preferredCurrency: z.string().min(1, 'Preferred currency is required'),
  enableNotifications: z.boolean().default(false),
});

type AccountSetupFormValues = z.infer<typeof accountSetupSchema>;

// --- Placeholder tRPC Hook ---
// In a real application, this would be generated by tRPC.
const useSetupAccount = () => {
  return useMutation({
    mutationFn: async (data: AccountSetupFormValues) => {
      // Simulate API call
      return new Promise((resolve) => {
        setTimeout(() => {
          console.log('Submitting account setup:', data);
          resolve({ success: true, message: 'Account setup successful!' });
        }, 1500);
      });
    },
  });
};

const AccountSetup: React.FC = () => {
  const { register, handleSubmit, formState: { errors }, watch } = useForm<AccountSetupFormValues>({
    resolver: zodResolver(accountSetupSchema),
    defaultValues: {
      walletAddress: '',
      preferredCurrency: 'USD',
      enableNotifications: false,
    },
  });

  const { mutate, isLoading, isError, isSuccess, error } = useSetupAccount();

  const onSubmit = (data: AccountSetupFormValues) => {
    mutate(data);
  };

  const enableNotifications = watch('enableNotifications');

  return (
    <div className="flex items-center justify-center min-h-screen bg-background p-4">
      <Card className="w-full max-w-md">
        <CardHeader>
          <CardTitle className="text-2xl font-bold">Crypto Account Setup</CardTitle>
          <CardDescription>Configure your cryptocurrency account settings.</CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
            <div className="grid gap-2">
              <Label htmlFor="walletAddress">Wallet Address</Label>
              <Input
                id="walletAddress"
                type="text"
                placeholder="0x..."
                {...register('walletAddress')}
                aria-invalid={errors.walletAddress ? "true" : "false"}
              />
              {errors.walletAddress && (
                <p className="text-sm text-red-500" role="alert">{errors.walletAddress.message}</p>
              )}
            </div>

            <div className="grid gap-2">
              <Label htmlFor="preferredCurrency">Preferred Currency</Label>
              <Input
                id="preferredCurrency"
                type="text"
                placeholder="USD"
                {...register('preferredCurrency')}
                aria-invalid={errors.preferredCurrency ? "true" : "false"}
              />
              {errors.preferredCurrency && (
                <p className="text-sm text-red-500" role="alert">{errors.preferredCurrency.message}</p>
              )}
            </div>

            <div className="flex items-center justify-between space-x-2">
              <Label htmlFor="enableNotifications">Enable Notifications</Label>
              <Switch
                id="enableNotifications"
                checked={enableNotifications}
                {...register('enableNotifications')}
                aria-checked={enableNotifications}
              />
            </div>

            <Button type="submit" className="w-full" disabled={isLoading}>
              {isLoading ? 'Setting up...' : 'Save Account Settings'}
            </Button>

            {isError && (
              <p className="text-sm text-red-500" role="alert">Error: {error?.message || 'Failed to set up account.'}</p>
            )}
            {isSuccess && (
              <p className="text-sm text-green-500" role="status">Account setup successful!</p>
            )}
          </form>
        </CardContent>
      </Card>
    </div>
  );
};

export default AccountSetup;
